381→  content: string,
382→): AutoReviewMarker | null {
383→  const matches = content.match(REVIEW_MARKER_REGEX);
384→  if (!matches || matches.length === 0) {
385→    return null;
386→  }
387→
388→  const latest = matches[matches.length - 1];
389→  if (!latest) {
390→    return null;
391→  }
392→
393→  let verdict = "";
394→  let hash = "";
395→  const fields = latest.matchAll(/(\w+)=([^;]+)/g);
396→  for (const field of fields) {
397→    const key = field[1]?.trim();
398→    const value = field[2]?.trim();
399→    if (!key || !value) {
400→      continue;
401→    }
402→    if (key === "verdict") {
403→      verdict = value;
404→    } else if (key === "hash") {
